diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index 8d5866e98a8e..7774de1f4851 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -487,6 +487,13 @@ Instruction *InstCombinerImpl::visitMul(BinaryOperator &I) {
                                     m_c_UMin(m_Deferred(X), m_Deferred(Y))))))
     return BinaryOperator::CreateWithCopiedFlags(Instruction::Mul, X, Y, &I);

+  // (select C, A, B) * (select C, B, A) => A * B
+  Value *Cond, *TrueVal0, *FalseVal0, *TrueVal1, *FalseVal1;
+  if (match(Op0, m_Select(m_Value(Cond), m_Value(TrueVal0), m_Value(FalseVal0))) &&
+      match(Op1, m_Select(m_Value(Cond), m_Value(TrueVal1), m_Value(FalseVal1))) &&
+      TrueVal0 == FalseVal1 && FalseVal0 == TrueVal1)
+    return BinaryOperator::CreateWithCopiedFlags(Instruction::Mul, TrueVal0, FalseVal0, &I);
+
   // (mul Op0 Op1):
   //    if Log2(Op0) folds away ->
   //        (shl Op1, Log2(Op0))
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..d44661f42dad 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1133,6 +1133,14 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,

   if (LHSIsSelect && RHSIsSelect && A == D) {
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
+    // If the operation is commutative and the operands are swapped,
+    // the select can be eliminated entirely:
+    // (A ? B : C) op (A ? C : B) -> B op C
+    if (I.isCommutative() && B == F && C == E) {
+      if (Value *V = simplifyBinOp(Opcode, B, E, FMF, Q))
+        return V;
+      return Builder.CreateBinOp(Opcode, B, E, I.getName());
+    }
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);
     False = simplifyBinOp(Opcode, C, F, FMF, Q);

